def count_up_to(n):
    """Return an array of prime numbers less than a given non-negative integer n."""

    if n < 2:
        return []

    def is_prime(num):
        """Check if a number is prime."""
        if num < 2:
            return False
        for i in range(2, int(num**0.5) + 1):
            if num % i == 0:
                return False
        return True

    primes = []
    for i in range(2, n):
        if is_prime(i):
            primes.append(i)

    return primes

